import './App.css';

function App() {
  return (
    <div className="App">
      <div className="top-nav">
        <a href="/" className="brand-button">LingoParrot</a>
      </div>

      <header className="App-header">
        <h1 className="App-title">LingoParrot</h1>
        <p className="App-tagline">Conversation Based Language Learning Companion</p>
        <nav className="App-nav">
          <button className="nav-button">Start Learning</button>
          <button className="nav-button">Vocabulary</button>
          <button className="nav-button">Practice</button>
          <button className="nav-button">Profile</button>
        </nav>
      </header>
    </div>
  );
}

export default App;
